1	type Cell = number[];
2	
3	function isNeighbor(a: Cell, b: Cell): boolean {
4	  const isSameCell = a[0] === b[0] && a[1] === b[1];
5	  return (
6	    !isSameCell && Math.abs(a[0] - b[0]) <= 1 && Math.abs(a[1] - b[1]) <= 1
7	  );
8	}
9	
10	function countLiveNeighbors(cell: Cell, liveCells: Cell[]): number {
11	  return liveCells.filter((other) => isNeighbor(cell, other)).length;
12	}
13	
14	export function nextGeneration(grid: Cell[]): Cell[] {
15	  return grid.filter((cell) => {
16	    const liveNeighbors = countLiveNeighbors(cell, grid);
17	    return liveNeighbors === 2 || liveNeighbors === 3;
18	  });
19	}
